import 'package:injectable/injectable.dart'; import '../../../core/utils/app_logger.dart'; @injectable class AccessibilityHelper { bool _serviceEnabled = false; bool get isEnabled => _serviceEnabled; Future<bool> checkAccessibility() async { AppLogger.info('Accessibility check: (requires AccessibilityService on Android)'); return _serviceEnabled; } Future<void> enable() async { _serviceEnabled = true; } Future<void> disable() async { _serviceEnabled = false; } }